import os
import numpy as np
from flask import Flask, request, jsonify
from sklearn.preprocessing import LabelEncoder
from sklearn.svm import SVC
from PIL import Image
import face_recognition

app = Flask(__name__)

# Load employee photos and labels
def load_data(data_dir):
    images = []
    labels = []
    for label in os.listdir(data_dir):
        label_path = os.path.join(data_dir, label)
        if os.path.isdir(label_path):
            for img_name in os.listdir(label_path):
                img_path = os.path.join(label_path, img_name)
                image = face_recognition.load_image_file(img_path)
                images.append(image)
                labels.append(label)
    return np.array(images), np.array(labels)

# Encode faces
def encode_faces(images):
    encodings = []
    for image in images:
        face_encodings = face_recognition.face_encodings(image)
        if len(face_encodings) > 0:
            encodings.append(face_encodings[0])
    return np.array(encodings)

# Train model
def train_model(encodings, labels):
    le = LabelEncoder()
    y = le.fit_transform(labels)
    model = SVC(probability=True)
    model.fit(encodings, y)
    return model, le

# Load data and train model
data_dir = 'path/to/employee/photos'
images, labels = load_data(data_dir)
encodings = encode_faces(images)
model, label_encoder = train_model(encodings, labels)

@app.route('/recognize', methods=['POST'])
def recognize():
    if 'image' not in request.files:
        return jsonify({'error': 'No image provided'}), 400
    file = request.files['image']
    img = face_recognition.load_image_file(file)
    face_encodings = face_recognition.face_encodings(img)
    if len(face_encodings) == 0:
        return jsonify({'error': 'No face detected in the image'}), 400
    
    encoding = face_encodings[0]
    probabilities = model.predict_proba([encoding])[0]
    confidence_scores = dict(zip(label_encoder.classes_, probabilities))
    
    return jsonify(confidence_scores)

if __name__ == '__main__':
    app.run(debug=True)